+	it("throws on invalid port", async () => {
+		await expect(() =>
+			webhookCommand({ port: "70000", path: "/hook" }, deps, runtime),
+		).rejects.toThrow("Port must be between 1 and 65535");
+	});
+
+	it("logs dry run instead of starting server", async () => {
+		runtime.log.mockClear();
