+		expect(exec).toHaveBeenCalledWith("which", ["node"]);
+	});
+
+	it("logs and exits when missing", async () => {
+		const exec: typeof runExec = vi
+			.fn()
+			.mockRejectedValue(new Error("missing"));
+		const error = vi.fn();
+		const exit = vi.fn(() => {
+			throw new Error("exit");
+		});
